void calcularSumaYConteo(const vector<int>& datos, int& suma, int& conteo) {
    // Inicializar variables
    int minimo = INT_MAX;
    suma = 0;
    conteo = 0;
    // Encontrar el mínimo
    for (int valor : datos) {
        if (valor < minimo) {
            minimo = valor;
        }
    }
    // Calcular suma y conteo excluyendo el mínimo
    for (int valor : datos) {
        if (valor != minimo) {
            suma += valor;
            conteo++;
        }
    }
}

